FROM jsonb_to_recordset('[{"id": "cap-108-english-reading-passage-16", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-108-english-reading", "question_type": "reading_passage", "question_text": "(16-17)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Making goulash                        16. What are “Daddy and me” doing in the poem?\n(A) Eating.\nwe don’t talk much,\n(B) Singing.\nDaddy and me.\n(C) Dancing.\n(D) Cooking.\n“The talking’s in the making, son,”\nhe smiles.                            17. What can we most likely know about the\nI see what he means.                      speaker?\n(A) He seldom understands his father.\nIt’s in the knife                         (B) He enjoys his time with his father.\nmeeting the beef,                         (C) He often makes goulash for his father.\n(D) He wants to be as famous as his father.\nin the dancing of potatoes\n likely 可能\nas they turn in the water,\nin the singing\nof boiling soup in the pot.\nThere are enough words\nin the way\nDaddy teaches me his famous dish\nand the way he hugs me\nwhen we finish.\nMaking goulash\nwe don’t talk much,\nDaddy and me,\nbut everything is said.\n(Ideas from Candace Pearson’s poem)\n poem 詩", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "c53c93460131", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": null, "intro_line": "(16-17)", "child_qnums": [16, 17]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-108-english-reading-passage-18", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-108-english-reading", "question_type": "reading_passage", "question_text": "(18-19)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "City Sight Bus\nwww.citysightbus.org\n&HQWUDO\u00036WDWLRQ\n)DUPHUV熎\u0003%ULGJH\n4XHHQ\u0003\n0DUJXHULWH熎V\u0003\n3DUN\n(DVW\u0010(QG\u0003\n:HVWVLGH\u0003&KXUFK                  7HPSOH\n6WDUOLJKW\u0003\n*DUGHQ                                                .LQJ\u0003+HQU\\熎V\u0003&DVWOH\n*UDQG\u0003&DVWOH\u0003\n*UHDW\u0003$JH\u0003         RI\u0003.LQJ\u0003&KDUOHV\n7KHDWHU\n/RYHUVĬ\u0003         .LQJ\u0003+HQU\\熎V\u0003\n%ULGJH              *DUGHQ\n&LW\\\u00036TXDUH\n.LQJ\u0003-DPHV熎\u0003&DVWOH\nOPENING HOURS\nHigh Season (April to September): 9:00 – 18:00 every day\nLow Season (October to March): 9:00 – 17:00 every day\nTICKET PRICES\nLine A (                    ): $20 each person\nLine B (                    ): $18 each person\nTHINGS YOU SHOULD KNOW\nBuses for both lines leave every hour from Central Station.\nLine A takes one hour; Line B takes 50 minutes.\nIf you are taking your pet with you, please buy a seat for it at half price.\nSave 10% if you buy tickets on the Internet.\nSave 10% if you buy tickets for both lines.\nGo to www.citysightbus.org for more information.", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "c53c93460131", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": null, "intro_line": "(18-19)", "child_qnums": [18, 19]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-108-english-reading-passage-20", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-108-english-reading", "question_type": "reading_passage", "question_text": "(20-22)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Sarah: You’re VERY popular today. I’ve had seventeen calls asking for you.\nMike: Finally! After all these years of kicking and running, I’ve got my own fans!\nSo what did they want? My photos? Do I need to sign my name? Are they\nstarting a fan club for me?\nSarah: Well, let me ask you this: What day was yesterday?\nMike: Friday… Why?\nSarah: Did you forget something?\nMike: Did I forget… OH, NO! I didn’t pick up my soccer team’s sport shirts from\nthe shop! And we’re having this big game tomorrow!\nSarah: Yeah. And from what I’ve heard, it’s your team’s most important game this season.\nMike: OK. I have to go fix this now.\nSarah: Too late. They’ve tried. It’s not open on the weekend. And if you want to\nknow, they are Johnny, Ricky, Archie, Freddie…\nMike: I know, I know, everyone on my team. Oh, I’m a dead man now.\nSarah: Yeah, that was what they said on the phone, seventeen times.", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "c53c93460131", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": null, "intro_line": "(20-22)", "child_qnums": [20, 21, 22]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-108-english-reading-passage-23", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-108-english-reading", "question_type": "reading_passage", "question_text": "(23-25)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "''(&\n\u0015\u0013\u0014\u0019\nAnimals have their special ways to deal with hard times in nature.\nThe superb fairy-wren, one kind of bright-blue bird in Australia, is one\nexample. This year, a ten-year study showed that this small bird has\neggs of different sizes in different kinds of weather. When the weather\nis hot and dry, there is less food for young superb fairy-wrens, and they\ndie easily. So the mother bird will make larger eggs to help her babies\ngrow stronger inside before they break out of the eggs into the “hungry”\nworld.\nHowever, not all mother birds are able to do this trick. Only those\nwith at least one male child can. When the weather is “good,”\nthe mother will make smaller eggs, and her sons will bring\nfood back for their baby brothers and sisters from the eggs.\nWith her sons’ help, the mother can save more energy to make\nlarger eggs when the weather is bad. Isn’t this amazing?\n male 雄性 energy 能量", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "c53c93460131", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": null, "intro_line": "(23-25)", "child_qnums": [23, 24, 25]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-108-english-reading-passage-26", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-108-english-reading", "question_type": "reading_passage", "question_text": "(26-28)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Here are two pieces of news that Annie collected for her report.\nPapier-mâché is works of art that are made of paper.\nIn Taiwan, it is known as zhizha and is usually burned as\na gift for dead people. Taiwan’s papier-mâché is dying\nbecause it is not much needed now. However, this dying\nart won a Frenchman’s heart when he visited the island.\nHe then invited one of the papier-mâché shops, Hsin\nHsin Paper Offering Store, to show their beautiful works\nin France. The shop owner’s son also used papier-\nmâché in a way that no one ever thought of—making a\nmovie with it.\nStan Lai is very important in Taiwan’s theater. He brought changes to Chinese\ntheater art of the old days to make it closer to our life experiences and easier to\nunderstand. One of his most famous works is That Evening,\nWe Performed Crosstalk (1985). It was such a smash hit that\npeople became interested again in xiangsheng, a show of funny\ntalk between two actors. This art used to be a hobby that only\na few people shared, but Lai has opened a bigger market for it.\nNow it has fans across all ages.\n work 作品", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "c53c93460131", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": null, "intro_line": "(26-28)", "child_qnums": [26, 27, 28]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-108-english-reading-passage-29", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-108-english-reading", "question_type": "reading_passage", "question_text": "(29-32)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "VOF News                                                   16/01/2015\nFor many people, having a cup of coffee right out of\nbed is the best way to start a day. But a report from Asap\nScience says otherwise. It says the worst time for coffee is\nsoon after we get up. When we wake up, our bodies start\nto make cortisol. Cortisol helps us to think clearly and be\nquick to understand and act. The cortisol levels rise after we wake up\nand climb to the highest in about an hour. So there are two problems\nwhen we drink coffee during this time: (1) our bodies will make less\ncortisol, and (2) the cortisol will make coffee less useful. And that’s why\nsome of us drink more and more coffee.\nThen, when’s the best time to have coffee? When the cortisol levels\nare going down, the report says. Cortisol levels are usually highest\nbetween 8 a.m. and 9 a.m., between noon and 1 p.m., and between 5:30\np.m. and 6:30 p.m. So if you want to have coffee, enjoy it after these\ntimes, and this popular drink will help you the most.\n cortisol 皮質醇 level 數值；濃度", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "c53c93460131", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": null, "intro_line": "(29-32)", "child_qnums": [29, 30, 31, 32]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-108-english-reading-passage-33", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-108-english-reading", "question_type": "reading_passage", "question_text": "(33-35)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Below is part of a new shopping center’s market report.\nOur busiest time is weekend afternoons, between 1:30 p.m. and 3:30 p.m.\nAbout half the business of the week is done then. So it would be better if\nwe move Weekend’s Best Buy from Saturday evening to Saturday afternoon\nwhen there may be more shoppers during the sale. We should also think\nabout having more free buses during the weekend, as 75% of the shoppers\nwho were interviewed said two buses an hour are just not enough.\nWeekend evenings are second busiest, though it is not as good as last season.\nAn interesting fact is that business is better on weekday evenings, usually\none hour before closing, than on weekend mornings. Most of the shoppers\nthen are people who live near or working parents who do their last-minute\nshopping. They together make up almost 60% of the business\non weekday evenings. It might bring in more business if we\nopen half an hour longer during weekdays, until 10:30 p.m.\n as 由於 make up 構成；組成", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "c53c93460131", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": null, "intro_line": "(33-35)", "child_qnums": [33, 34, 35]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-108-english-reading-passage-36", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-108-english-reading", "question_type": "reading_passage", "question_text": "(36-37)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Dear Maggie,\nI know you won’t be happy but I still have to say this again. It hurts me\nto think that you’re going to   36  . I know you’ve always wanted to be\nlike those actresses with big eyes and slim legs, but in fact you are already\nbeautiful. What you are born with makes you special because nobody\nlooks the same as you.\nIt worries me more that   37  . But sadly, there’s no quick fix to this,\nnot even with the doctor’s help. If you don’t try to like yourself first, no\none else will. People like you not because of your face, but because of\nyour heart. You need to understand this first. Until you understand this,\nnothing is going to be different even if you have this change.\nI truly hope you think this through again.\nLove,\nLinda", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "c53c93460131", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": null, "intro_line": "(36-37)", "child_qnums": [36, 37]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-108-english-reading-passage-38", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-108-english-reading", "question_type": "reading_passage", "question_text": "(38-41)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Elizabeth Alexandra Mary Windsor was born in London on April\n21, 1926. No one thought one day she   38   the queen of the UK.\nAfter her grandfather, King George V, died in 1936, Elizabeth’s uncle,\nPrince Edward, became King Edward VIII. Edward   39   in love\nwith a married American woman long before, and he decided to marry\nher after he became the king. However, Edward was asked to choose\nbetween the throne and his love. Finally, he decided to give up the\nthrone.\n40  . After Edward VIII gave up the throne, Elizabeth’s father\nbecame King George VI. As the oldest child without any brothers,\nElizabeth became next in line to the throne. She needed to say goodbye\nto her good old life and prepare to be a queen. After her father died in\n1952, she became Queen Elizabeth II.\nEver since she became head of her country, Queen Elizabeth II\n41  : She has held meetings with important people in the UK, and\nhas visited many foreign countries. In the few hours she keeps to herself,\nhowever, she reads and enjoys horseback riding.\n throne 王位", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:39+00:00", "source_pdf_sha1": "c53c93460131", "answer_pdf_sha1": "71bcc8be1a46", "flags": [], "parse_confidence": null, "intro_line": "(38-41)", "child_qnums": [38, 39, 40, 41]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
